using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class VictoryPanel : MonoBehaviour
    {
        [Header("Title")]
        [SerializeField] private Text _titleText;

        [Header("Stars")]
        [SerializeField] private Image[] _starImages = new Image[3];
        [SerializeField] private Sprite _starFilledSprite;
        [SerializeField] private Sprite _starEmptySprite;

        [Header("Stats")]
        [SerializeField] private Text _killCountText;
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _waveText;

        [Header("Buttons")]
        [SerializeField] private Button _restartButton;
        [SerializeField] private Button _nextLevelButton;
        [SerializeField] private Button _mainMenuButton;

        private void Awake()
        {
            if (_restartButton != null)
                _restartButton.onClick.AddListener(OnRestartClicked);
            if (_nextLevelButton != null)
                _nextLevelButton.onClick.AddListener(OnNextLevelClicked);
            if (_mainMenuButton != null)
                _mainMenuButton.onClick.AddListener(OnMainMenuClicked);
        }

        private void OnDestroy()
        {
            if (_restartButton != null)
                _restartButton.onClick.RemoveListener(OnRestartClicked);
            if (_nextLevelButton != null)
                _nextLevelButton.onClick.RemoveListener(OnNextLevelClicked);
            if (_mainMenuButton != null)
                _mainMenuButton.onClick.RemoveListener(OnMainMenuClicked);
        }

        public void ShowVictory()
        {
            gameObject.SetActive(true);
            UpdateStats();
            UpdateStars();
        }

        public void HideVictory()
        {
            gameObject.SetActive(false);
        }

        private void UpdateStats()
        {
            var gm = GameManager.Instance;
            if (gm == null) return;

            if (_killCountText != null)
                _killCountText.text = gm.EnemiesKilled.ToString();
            if (_goldText != null)
                _goldText.text = gm.CurrentGold.ToString();
            if (_waveText != null)
                _waveText.text = $"{gm.CurrentWave}/{gm.TotalWaves}";
        }

        private void UpdateStars()
        {
            var gm = GameManager.Instance;
            if (gm == null) return;

            int starCount = CalculateStars(gm);
            for (int i = 0; i < _starImages.Length; i++)
            {
                if (_starImages[i] == null) continue;
                if (_starFilledSprite != null && _starEmptySprite != null)
                {
                    _starImages[i].sprite = i < starCount ? _starFilledSprite : _starEmptySprite;
                }
                else
                {
                    _starImages[i].color = i < starCount
                        ? new Color(1f, 0.85f, 0f, 1f)
                        : new Color(0.3f, 0.3f, 0.3f, 0.5f);
                }
            }
        }

        private int CalculateStars(GameManager gm)
        {
            float lifeRatio = (float)gm.CurrentLife / 20f;
            if (lifeRatio >= 0.7f) return 3;
            if (lifeRatio >= 0.4f) return 2;
            return 1;
        }

        private void OnRestartClicked()
        {
            HideVictory();
            GameManager.Instance.RestartGame();
        }

        private void OnNextLevelClicked()
        {
            HideVictory();
            int nextIndex = GameManager.Instance.CurrentLevelData != null ? 1 : 0;
            var levels = GameManager.Instance.Levels;
            if (levels != null && nextIndex < levels.Length)
            {
                GameManager.Instance.LoadLevel(nextIndex);
            }
            else
            {
                SceneManager.LoadScene(SceneManager.GetActiveScene().name);
            }
        }

        private void OnMainMenuClicked()
        {
            HideVictory();
            if (ModuleModeDetector.IsModuleMode)
            {
                // 从家园进入时，返回家园
                SceneManager.LoadScene("HomeScene");
            }
            else
            {
                SceneManager.LoadScene("MainMenu");
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class GameUI : MonoBehaviour
    {
        [Header("Top Bar")]
        [SerializeField] private Image _goldIcon;
        [SerializeField] private Text _goldText;
        [SerializeField] private Image _lifeIcon;
        [SerializeField] private Text _lifeText;
        [SerializeField] private Image _waveIcon;
        [SerializeField] private Text _waveText;

        [Header("Wave Info")]
        [SerializeField] private GameObject _waveInfoPanel;
        [SerializeField] private Text _waveTimerText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Button _startWaveButton;

        [Header("Tower Selection")]
        [SerializeField] private GameObject _towerSelectPanel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;

        [Header("Tower Info")]
        [SerializeField] private GameObject _towerInfoPanel;
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _towerDamageText;
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;

        [Header("Game Controls")]
        [SerializeField] private Button _pauseButton;
        [SerializeField] private Button _speedButton;
        [SerializeField] private GameObject _pauseMenu;
        [SerializeField] private GameObject _gameOverPanel;
        [SerializeField] private GameObject _victoryPanel;

        [Header("Settings")]
        [SerializeField] private Slider _volumeSlider;
        [SerializeField] private Toggle _soundToggle;

        private Tower.TowerSlot _selectedSlot;
        private Tower.Tower _selectedTower;

        private void Start()
        {
            InitializeUI();
            SubscribeToEvents();
        }

        private void InitializeUI()
        {
            if (_pauseMenu != null) _pauseMenu.SetActive(false);
            if (_gameOverPanel != null) _gameOverPanel.SetActive(false);
            if (_victoryPanel != null) _victoryPanel.SetActive(false);
            if (_towerInfoPanel != null) _towerInfoPanel.SetActive(false);
            if (_towerSelectPanel != null) _towerSelectPanel.SetActive(false);

            UpdateGoldDisplay(GameManager.Instance.CurrentGold);
            UpdateLifeDisplay(GameManager.Instance.CurrentLife);
            UpdateWaveDisplay(GameManager.Instance.CurrentWave);

            if (_startWaveButton != null)
            {
                _startWaveButton.onClick.AddListener(OnStartWaveClicked);
            }
            if (_pauseButton != null)
            {
                _pauseButton.onClick.AddListener(OnPauseClicked);
            }
            if (_speedButton != null)
            {
                _speedButton.onClick.AddListener(OnSpeedClicked);
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }
            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }
        }

        private void SubscribeToEvents()
        {
            GameManager.Instance.OnGoldChanged += UpdateGoldDisplay;
            GameManager.Instance.OnLifeChanged += UpdateLifeDisplay;
            GameManager.Instance.OnWaveChanged += UpdateWaveDisplay;
            GameManager.Instance.OnStateChanged += OnGameStateChanged;

            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Subscribe<LifeChangedEvent>(OnLifeChanged);
        }

        private void OnDestroy()
        {
            if (GameManager.Instance != null)
            {
                GameManager.Instance.OnGoldChanged -= UpdateGoldDisplay;
                GameManager.Instance.OnLifeChanged -= UpdateLifeDisplay;
                GameManager.Instance.OnWaveChanged -= UpdateWaveDisplay;
                GameManager.Instance.OnStateChanged -= OnGameStateChanged;
            }

            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Unsubscribe<LifeChangedEvent>(OnLifeChanged);
        }

        #region Display Updates

        private void UpdateGoldDisplay(int gold)
        {
            if (_goldText != null)
            {
                _goldText.text = gold.ToString();
            }

            if (_goldIcon != null)
            {
                _goldIcon.enabled = true;
            }
        }

        private void UpdateLifeDisplay(int life)
        {
            if (_lifeText != null)
            {
                _lifeText.text = life.ToString();
            }

            if (_lifeIcon != null)
            {
                _lifeIcon.enabled = true;
            }
        }

        private void UpdateWaveDisplay(int wave)
        {
            if (_waveText != null)
            {
                _waveText.text = $"{wave}/{GameManager.Instance.TotalWaves}";
            }

            if (_waveIcon != null)
            {
                _waveIcon.enabled = true;
            }
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateGoldDisplay(e.CurrentGold);
        }

        private void OnLifeChanged(LifeChangedEvent e)
        {
            UpdateLifeDisplay(e.CurrentLife);
        }

        #endregion

        #region Tower Selection

        public void ShowTowerSelectPanel(Tower.TowerSlot slot)
        {
            _selectedSlot = slot;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(true);
            }
        }

        public void HideTowerSelectPanel()
        {
            _selectedSlot = null;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(false);
            }
        }

        public void SelectTower(Data.TowerData towerData)
        {
            if (_selectedSlot != null)
            {
                _selectedSlot.PlaceTower(towerData);
                HideTowerSelectPanel();
            }
        }

        #endregion

        #region Tower Info

        public void ShowTowerInfo(Tower.Tower tower)
        {
            _selectedTower = tower;

            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(true);
            }

            UpdateTowerInfo();
        }

        public void HideTowerInfo()
        {
            _selectedTower = null;
            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_selectedTower == null) return;

            if (_towerNameText != null)
            {
                _towerNameText.text = _selectedTower.Data.towerName;
            }
            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"Level: {_selectedTower.CurrentLevel}";
            }
            if (_towerDamageText != null)
            {
                _towerDamageText.text = $"Damage: {_selectedTower.CurrentStats.damage}";
            }
            if (_upgradeCostText != null)
            {
                int cost = _selectedTower.GetUpgradeCost();
                _upgradeCostText.text = cost > 0 ? cost.ToString() : "MAX";
            }
            if (_sellValueText != null)
            {
                _sellValueText.text = _selectedTower.GetSellValue().ToString();
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.interactable = !_selectedTower.IsMaxLevel;
            }
        }

        #endregion

        #region Button Handlers

        private void OnStartWaveClicked()
        {
            Wave.WaveManager waveManager = FindObjectOfType<Wave.WaveManager>();
            if (waveManager != null)
            {
                waveManager.ForceStartWave();
            }

            if (_startWaveButton != null)
            {
                _startWaveButton.gameObject.SetActive(false);
            }
        }

        private void OnPauseClicked()
        {
            GameManager.Instance.TogglePause();

            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(GameManager.Instance.CurrentState == GameState.Paused);
            }
        }

        private void OnSpeedClicked()
        {
            float currentSpeed = GameManager.Instance.GameSpeed;
            float newSpeed = currentSpeed >= 3f ? 1f : currentSpeed + 1f;

            if (_speedButton != null)
            {
                Text textComponent = _speedButton.GetComponentInChildren<Text>();
                if (textComponent != null)
                {
                    textComponent.text = $"{newSpeed}x";
                }
            }
        }

        private void OnUpgradeClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Upgrade();
                UpdateTowerInfo();
            }
        }

        private void OnSellClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Sell();
                HideTowerInfo();
            }
        }

        #endregion

        #region Game State

        private void OnGameStateChanged(GameState state)
        {
            switch (state)
            {
                case GameState.Paused:
                    ShowPauseMenu();
                    break;
                case GameState.Playing:
                    HidePauseMenu();
                    break;
                case GameState.GameOver:
                    ShowGameOver();
                    break;
                case GameState.Victory:
                    ShowVictory();
                    break;
            }
        }

        private void ShowPauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(true);
            }
        }

        private void HidePauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(false);
            }
        }

        private void ShowGameOver()
        {
            if (_gameOverPanel != null)
            {
                _gameOverPanel.SetActive(true);
            }
        }

        private void ShowVictory()
        {
            if (_victoryPanel != null)
            {
                _victoryPanel.SetActive(true);
            }
        }

        #endregion

        #region Wave Timer

        public void UpdateWaveTimer(float time)
        {
            if (_waveTimerText != null)
            {
                if (time > 0)
                {
                    _waveTimerText.text = $"Next Wave: {Mathf.CeilToInt(time)}s";
                }
                else
                {
                    _waveTimerText.text = "Wave In Progress";
                }
            }
        }

        public void UpdateEnemyCount(int count)
        {
            if (_enemyCountText != null)
            {
                _enemyCountText.text = $"Enemies: {count}";
            }
        }

        #endregion
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Data
{
    [CreateAssetMenu(fileName = "LevelData", menuName = "TowerDefense/LevelData")]
    public class LevelData : ScriptableObject
    {
        public string levelName;
        public string sceneName;
        public Sprite previewImage;
        public int unlockCost;
        public bool isUnlocked;

        [Header("Tilemap Layout")]
        [Tooltip("用字符画地图: G=草地 P=路径 B=建塔位 D=装饰 S=起点 E=终点 .=空\n从上到下，第0行是最上面一行")]
        [TextArea(3, 30)]
        public string[] mapRows;

        [Header("Map Settings")]
        public Vector2 mapSize;
        public List<PathData> paths = new List<PathData>();
        public List<TowerSlotData> towerSlots = new List<TowerSlotData>();

        [Header("Wave Settings")]
        public int waveCount = 5;
        public List<WaveData> waves = new List<WaveData>();
        public float timeBetweenWaves = 10f;

        [Header("Rewards")]
        public int star1Requirement;
        public int star2Requirement;
        public int star3Requirement;
        public int goldReward;

        [Header("Initial Resources")]
        public int initialGold = 100;
        public int initialLife = 20;

        [Serializable]
        public struct PathData
        {
            public string pathName;
            public List<Vector3> waypoints;
        }

        [Serializable]
        public struct TowerSlotData
        {
            public Vector3 position;
            public SlotType slotType;
        }

        public enum SlotType
        {
            Normal,
            Premium,
            Restricted
        }

        public int MapWidth => mapRows?.Length > 0 ? mapRows[0].Length : 0;
        public int MapHeight => mapRows?.Length ?? 0;
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Data
{
    [CreateAssetMenu(fileName = "WaveData", menuName = "TowerDefense/WaveData")]
    public class WaveData : ScriptableObject
    {
        public int waveNumber;
        public float waveDelay = 5f;
        public float spawnInterval = 1f;
        public List<WaveEnemy> enemies = new List<WaveEnemy>();

        [Serializable]
        public struct WaveEnemy
        {
            public EnemyData enemyData;
            public int count;
            public float spawnDelay;
            public string spawnPoint;
        }

        public int TotalEnemies
        {
            get
            {
                int total = 0;
                foreach (var enemy in enemies)
                {
                    total += enemy.count;
                }
                return total;
            }
        }
    }
}

using UnityEngine;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Utils;
using TowerDefense.Wave;

namespace TowerDefense.Enemy
{
    public class EnemySpawner : MonoBehaviour
    {
        [Header("Settings")]
        [SerializeField] private PathCreator _pathCreator;
        [SerializeField] private Transform _spawnPoint;

        private void Awake()
        {
            if (_pathCreator == null)
            {
                _pathCreator = FindObjectOfType<PathCreator>();
                if (_pathCreator != null)
                    Debug.Log("EnemySpawner: 自动找到 PathCreator - " + _pathCreator.gameObject.name);
                else
                    Debug.LogError("EnemySpawner: 找不到 PathCreator！");
            }
        }

        private Queue<EnemyData> _spawnQueue = new Queue<EnemyData>();
        private float _spawnTimer = 0f;
        private float _spawnInterval = 1f;
        private bool _isSpawning = false;
        private bool _allSpawned = false; // 标记是否所有敌人都已出生

        public bool IsSpawning => _isSpawning;
        public static int CurrentWaveId { get; private set; }
        public static int TotalEnemiesInWave { get; private set; }

        // 双保险：本波 HashSet 防止重复统计
        private static HashSet<GameObject> _killedEnemiesThisWave = new HashSet<GameObject>();

        public static int RemainingEnemies 
        { 
            get 
            { 
                int remaining = TotalEnemiesInWave - _killedEnemiesThisWave.Count;
                return remaining >= 0 ? remaining : 0;  // 保证非负
            } 
        }

        private void Update()
        {
            if (_isSpawning && _spawnQueue.Count > 0)
            {
                _spawnTimer += Time.deltaTime;

                if (_spawnTimer >= _spawnInterval)
                {
                    _spawnTimer = 0f;
                    SpawnEnemy();
                }
            }

            // 所有敌人都已出生，且全部死亡/到达终点，才通知波次完成
            if (_allSpawned && RemainingEnemies <= 0)
            {
                _isSpawning = false;
                _allSpawned = false;
                WaveManager.Instance?.OnWaveComplete();
            }
        }

        public static void EnemyBorn(GameObject enemy)
        {
            // 敌人出生时注册波次ID
            enemy.GetComponent<Enemy>()?.SetBirthWaveId(CurrentWaveId);
        }

        public static void OnEnemyKilled(GameObject enemy, int enemyWaveId)
        {
            // ✅ 双保险: HashSet去重 + 波次ID相等才统计
            if (!_killedEnemiesThisWave.Contains(enemy) && enemyWaveId == CurrentWaveId)
            {
                _killedEnemiesThisWave.Add(enemy);
                Debug.Log($"✅ 波次{CurrentWaveId}敌人死亡: {_killedEnemiesThisWave.Count}/{TotalEnemiesInWave}, 剩余: {RemainingEnemies}");
            }
        }

        public void StartWave(WaveData waveData)
        {
            _spawnQueue.Clear();

            // 波次递进，给新的ID
            CurrentWaveId++;
            TotalEnemiesInWave = 0;

            // ✅ 新波次: 清空死亡集合，防止死循环统计
            _killedEnemiesThisWave.Clear();

            foreach (var enemyGroup in waveData.enemies)
            {
                for (int i = 0; i < enemyGroup.count; i++)
                {
                    _spawnQueue.Enqueue(enemyGroup.enemyData);
                    TotalEnemiesInWave++;
                }
            }

            Debug.Log($"🌊 波次{CurrentWaveId}开始: 准备出生 {TotalEnemiesInWave} 个敌人");

            _spawnInterval = waveData.spawnInterval;
            _isSpawning = true;
            _allSpawned = false;
            _spawnTimer = 0f;

            Debug.Log($"Wave started! Enemies to spawn: {_spawnQueue.Count}");
        }

        private void SpawnEnemy()
        {
            if (_spawnQueue.Count == 0)
            {
                _allSpawned = true;
                return;
            }

            EnemyData enemyData = _spawnQueue.Dequeue();

            // 队列空了，标记所有敌人都已出生
            if (_spawnQueue.Count == 0)
            {
                _allSpawned = true;
            }

            if (enemyData == null || enemyData.enemyPrefab == null)
            {
                SpawnEnemy();
                return;
            }

            Vector3 spawnPos = _spawnPoint != null ? _spawnPoint.position : (_pathCreator != null ? _pathCreator.GetWaypoint(0) : transform.position);

            GameObject enemyObj = Instantiate(enemyData.enemyPrefab, spawnPos, Quaternion.identity);
            Enemy enemy = enemyObj.GetComponent<Enemy>();

            if (enemy != null && _pathCreator != null)
            {
                // ✅ 设置波次归属ID（HashSet去重统计要用）
                enemy.SetBirthWaveId(CurrentWaveId);
                enemy.Initialize(enemyData);
                enemy.StartMovement(_pathCreator);
            }

            Debug.Log($"Spawned enemy: {enemyData.enemyName}, 波次ID={CurrentWaveId}");
        }

        public void StopSpawning()
        {
            _isSpawning = false;
            _spawnQueue.Clear();
        }

        public Enemy GetClosestEnemy(Vector3 position, float maxDistance)
        {
            Enemy[] enemies = FindObjectsOfType<Enemy>();
            Enemy closestEnemy = null;
            float closestDistance = float.MaxValue;

            foreach (var enemy in enemies)
            {
                float distance = Vector3.Distance(position, enemy.transform.position);
                if (distance <= maxDistance && distance < closestDistance)
                {
                    closestDistance = distance;
                    closestEnemy = enemy;
                }
            }

            return closestEnemy;
        }

        public List<Enemy> GetEnemiesInRange(Vector3 position, float range)
        {
            List<Enemy> enemiesInRange = new List<Enemy>();
            Enemy[] enemies = FindObjectsOfType<Enemy>();

            foreach (var enemy in enemies)
            {
                float distance = Vector3.Distance(position, enemy.transform.position);
                if (distance <= range)
                {
                    enemiesInRange.Add(enemy);
                }
            }

            return enemiesInRange;
        }

        private void OnDrawGizmos()
        {
            Gizmos.color = Color.cyan;
            Vector3 spawnPos = _spawnPoint != null ? _spawnPoint.position : transform.position;
            Gizmos.DrawSphere(spawnPos, 0.3f);
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Tilemaps;
using TowerDefense.Data;

namespace TowerDefense.Map
{
    public class LevelBuilder : MonoBehaviour
    {
        [Header("Tilemaps")]
        [SerializeField] private Tilemap groundMap;
        [SerializeField] private Tilemap pathMap;
        [SerializeField] private Tilemap buildSlotMap;
        [SerializeField] private Tilemap decorationMap;

        [Header("Tile Assets")]
        [SerializeField] private TileBase grassTile;
        [SerializeField] private TileBase pathTile;
        [SerializeField] private TileBase buildSlotTile;
        [SerializeField] private TileBase decoStoneTile;
        [SerializeField] private TileBase decoGrassTile1;
        [SerializeField] private TileBase decoGrassTile2;
        [SerializeField] private TileBase decoGrassTile3;

        [Header("Path Tiles (Auto-selected)")]
        [SerializeField] private TileBase pathHorizontalTop;
        [SerializeField] private TileBase pathHorizontalBottom;
        [SerializeField] private TileBase pathVerticalLeft;
        [SerializeField] private TileBase pathVerticalRight;
        [SerializeField] private TileBase pathCornerTopRight;
        [SerializeField] private TileBase pathCornerTopLeft;
        [SerializeField] private TileBase pathCornerBottomRight;
        [SerializeField] private TileBase pathCornerBottomLeft;

        [Header("Prefabs")]
        [SerializeField] private GameObject towerSlotPrefab;

        private List<Tower.TowerSlot> _towerSlots = new List<Tower.TowerSlot>();
        private Vector3Int _startCell;
        private Vector3Int _endCell;

        public List<Tower.TowerSlot> TowerSlots => _towerSlots;
        public Vector3Int StartCell => _startCell;
        public Vector3Int EndCell => _endCell;

        public void BuildLevel(LevelData levelData)
        {
            if (levelData?.mapRows == null || levelData.mapRows.Length == 0)
            {
                Debug.LogError("LevelData has no map rows!");
                return;
            }

            ClearAll();

            int height = levelData.mapRows.Length;
            int width = levelData.mapRows[0].Length;

            // Populate a set of path/build cells for neighbor lookup
            var pathCells = new HashSet<Vector3Int>();
            var buildCells = new HashSet<Vector3Int>();
            var decoCells = new HashSet<Vector3Int>();

            // First pass: collect all cell positions
            for (int row = 0; row < height; row++)
            {
                string line = levelData.mapRows[row];
                for (int col = 0; col < Mathf.Min(line.Length, width); col++)
                {
                    char c = line[col];
                    var cell = new Vector3Int(col, height - 1 - row, 0);

                    switch (c)
                    {
                        case 'P': case 'S': case 'E':
                            pathCells.Add(cell);
                            if (c == 'S') _startCell = cell;
                            if (c == 'E') _endCell = cell;
                            break;
                        case 'B':
                            buildCells.Add(cell);
                            break;
                        case 'D':
                            decoCells.Add(cell);
                            break;
                    }
                }
            }

            // Second pass: paint tiles
            for (int row = 0; row < height; row++)
            {
                string line = levelData.mapRows[row];
                for (int col = 0; col < Mathf.Min(line.Length, width); col++)
                {
                    char c = line[col];
                    var cell = new Vector3Int(col, height - 1 - row, 0);

                    // Ground: fill everywhere that has content
                    if (c != '.')
                    {
                        groundMap.SetTile(cell, grassTile);
                    }

                    switch (c)
                    {
                        case 'P': case 'S': case 'E':
                            pathMap.SetTile(cell, SelectPathTile(cell, pathCells));
                            break;
                        case 'B':
                            buildSlotMap.SetTile(cell, buildSlotTile);
                            break;
                        case 'D':
                            decorationMap.SetTile(cell, PickRandomDeco());
                            break;
                    }
                }
            }

            // Generate TowerSlots
            GenerateTowerSlots();

            Debug.Log($"Level '{levelData.levelName}' built: {width}x{height}, " +
                      $"path={pathCells.Count}, build={buildCells.Count}, deco={decoCells.Count}");
        }

        private TileBase SelectPathTile(Vector3Int cell, HashSet<Vector3Int> pathCells)
        {
            bool up = pathCells.Contains(cell + Vector3Int.up);
            bool down = pathCells.Contains(cell + Vector3Int.down);
            bool left = pathCells.Contains(cell + Vector3Int.left);
            bool right = pathCells.Contains(cell + Vector3Int.right);

            // Diagonal neighbors - distinguish parallel rows from junctions
            bool upLeft = pathCells.Contains(cell + Vector3Int.up + Vector3Int.left);
            bool upRight = pathCells.Contains(cell + Vector3Int.up + Vector3Int.right);
            bool downLeft = pathCells.Contains(cell + Vector3Int.down + Vector3Int.left);
            bool downRight = pathCells.Contains(cell + Vector3Int.down + Vector3Int.right);

            // A "parallel row" means the perpendicular neighbor also extends in the
            // same horizontal/vertical direction (both diagonals on that side are path).
            bool upIsParallel = up && upLeft && upRight;
            bool downIsParallel = down && downLeft && downRight;
            bool leftIsParallel = left && upLeft && downLeft;
            bool rightIsParallel = right && upRight && downRight;

            // --- Horizontal road cells ---
            if (left && right)
            {
                // If there's a parallel row, use straight tile based on which half
                if (upIsParallel) return pathHorizontalBottom; // parallel above → bottom row
                if (downIsParallel) return pathHorizontalTop;  // parallel below → top row

                // No parallel row → junction cell, determine corner type
                if (up && !down) return pathHorizontalBottom; // junction above, still bottom
                if (down && !up) return pathHorizontalTop;     // junction below, still top

                // Both up and down are junctions (no parallel row)
                // Use diagonal analysis for corner type
                if (!downRight && upLeft) return pathCornerBottomRight;
                if (!downLeft && upRight) return pathCornerBottomLeft;
                if (!upRight && downLeft) return pathCornerTopRight;
                if (!upLeft && downRight) return pathCornerTopLeft;

                return up ? pathHorizontalBottom : pathHorizontalTop;
            }

            // --- Vertical road cells ---
            if (up && down)
            {
                if (rightIsParallel) return pathVerticalLeft;  // parallel right → left column
                if (leftIsParallel) return pathVerticalRight;  // parallel left → right column

                if (right && !left) return pathVerticalLeft;
                if (left && !right) return pathVerticalRight;

                // Both left and right are junctions
                if (!downRight && upLeft) return pathCornerBottomRight;
                if (!downLeft && upRight) return pathCornerBottomLeft;
                if (!upRight && downLeft) return pathCornerTopRight;
                if (!upLeft && downRight) return pathCornerTopLeft;

                return right ? pathVerticalLeft : pathVerticalRight;
            }

            // --- Simple corners: exactly 2 orthogonal neighbors ---
            if (up && right && !down && !left) return pathCornerBottomLeft;
            if (up && left && !down && !right) return pathCornerBottomRight;
            if (down && right && !up && !left) return pathCornerTopLeft;
            if (down && left && !up && !right) return pathCornerTopRight;

            // --- Edge cells (single perpendicular neighbor) ---
            if (left || right) return up ? pathHorizontalBottom : pathHorizontalTop;
            if (up || down) return right ? pathVerticalLeft : pathVerticalRight;

            return pathTile;
        }

        private TileBase PickRandomDeco()
        {
            float r = Random.value;
            if (r < 0.4f) return decoGrassTile1;
            if (r < 0.7f) return decoGrassTile2;
            if (r < 0.9f) return decoGrassTile3;
            return decoStoneTile;
        }

        private void GenerateTowerSlots()
        {
            if (buildSlotMap == null || towerSlotPrefab == null) return;

            _towerSlots.Clear();

            // 找到或创建 BuildSlots 父对象
            Transform buildSlotsParent = null;
            var existingParent = GameObject.Find("建造槽");
            if (existingParent == null) existingParent = GameObject.Find("BuildSlots");
            if (existingParent != null)
            {
                // 清除已有的旧 TowerSlot 子对象
                for (int i = existingParent.transform.childCount - 1; i >= 0; i--)
                {
                    DestroyImmediate(existingParent.transform.GetChild(i).gameObject);
                }
                buildSlotsParent = existingParent.transform;
            }

            BoundsInt bounds = buildSlotMap.cellBounds;

            for (int x = bounds.xMin; x < bounds.xMax; x++)
            {
                for (int y = bounds.yMin; y < bounds.yMax; y++)
                {
                    Vector3Int cellPosition = new Vector3Int(x, y, 0);
                    if (buildSlotMap.GetTile(cellPosition) == null) continue;

                    Vector3 worldPosition = buildSlotMap.CellToWorld(cellPosition);
                    worldPosition += new Vector3(0.5f, 0.5f, 0);

                    GameObject slotObj = Instantiate(towerSlotPrefab, worldPosition, Quaternion.identity);
                    slotObj.name = $"TowerSlot_{x}_{y}";

                    // 设置父对象
                    if (buildSlotsParent != null)
                    {
                        slotObj.transform.SetParent(buildSlotsParent, true);
                    }

                    Tower.TowerSlot slot = slotObj.GetComponent<Tower.TowerSlot>();
                    if (slot != null) _towerSlots.Add(slot);
                }
            }

            Debug.Log($"Generated {_towerSlots.Count} tower slots");
        }

        public void ClearAll()
        {
            // Destroy existing tower slots
            foreach (var slot in _towerSlots)
            {
                if (slot != null) Destroy(slot.gameObject);
            }
            _towerSlots.Clear();

            // Also destroy any TowerSlot objects in BuildSlots parent
            var buildSlotsObj = GameObject.Find("建造槽");
            if (buildSlotsObj == null) buildSlotsObj = GameObject.Find("BuildSlots");
            if (buildSlotsObj != null)
            {
                for (int i = buildSlotsObj.transform.childCount - 1; i >= 0; i--)
                {
                    DestroyImmediate(buildSlotsObj.transform.GetChild(i).gameObject);
                }
            }

            groundMap?.ClearAllTiles();
            pathMap?.ClearAllTiles();
            buildSlotMap?.ClearAllTiles();
            decorationMap?.ClearAllTiles();
        }

        /// <summary>
        /// Get ordered path waypoints from start to end by following path tiles.
        /// </summary>
        public List<Vector3> GetPathWaypoints()
        {
            var waypoints = new List<Vector3>();
            if (pathMap == null) return waypoints;

            var visited = new HashSet<Vector3Int>();
            var current = _startCell;

            while (current != null && !visited.Contains(current) && pathMap.GetTile(current) != null)
            {
                visited.Add(current);
                waypoints.Add(pathMap.CellToWorld(current) + new Vector3(0.5f, 0.5f, 0));

                if (current == _endCell) break;

                // Find next unvisited path neighbor
                Vector3Int? next = null;
                foreach (var dir in new[] { Vector3Int.up, Vector3Int.down, Vector3Int.left, Vector3Int.right })
                {
                    var neighbor = current + dir;
                    if (!visited.Contains(neighbor) && pathMap.GetTile(neighbor) != null)
                    {
                        next = neighbor;
                        break;
                    }
                }

                if (next.HasValue) current = next.Value;
                else break;
            }

            return waypoints;
        }
    }
}

using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Map;

namespace TowerDefense.Core
{
    public enum GameState
    {
        Menu,
        Playing,
        Paused,
        GameOver,
        Victory
    }

    public class GameManager : Singleton<GameManager>
    {
        [Header("Level Config")]
        [SerializeField] private LevelData[] _levels;
        [SerializeField] private LevelBuilder _levelBuilder;

        [Header("Game Settings")]
        [SerializeField] private int _initialGold = 500;
        [SerializeField] private int _initialLife = 20;
        [SerializeField] private float _gameSpeed = 1f;

        [Header("Debug")]
        [SerializeField] private bool _debugMode = false;

        private LevelData _currentLevelData;

        private GameState _currentState = GameState.Menu;
        private int _currentGold;
        private int _currentLife;
        private int _currentWave = 0;
        private int _totalWaves = 0;
        private int _enemiesKilled = 0;
        private float _gameTime = 0f;

        /// <summary>是否以模块模式运行</summary>
        private bool _isModuleMode;

        public GameState CurrentState => _currentState;
        public int CurrentGold => _currentGold;
        public int CurrentLife => _currentLife;
        public int CurrentWave => _currentWave;
        public int TotalWaves => _totalWaves;
        public int EnemiesKilled => _enemiesKilled;
        public float GameTime => _gameTime;
        public float GameSpeed => _gameSpeed;
        public bool IsPlaying => _currentState == GameState.Playing;
        public bool IsModuleMode => _isModuleMode;

        public System.Action<GameState> OnStateChanged;
        public System.Action<int> OnGoldChanged;
        public System.Action<int> OnLifeChanged;
        public System.Action<int> OnWaveChanged;

        protected override void Awake()
        {
            // 检测模块模式：通过场景名或全局标志判断
            _isModuleMode = ModuleModeDetector.IsModuleMode;

            if (_isModuleMode)
            {
                // 模块模式下不使用 DontDestroyOnLoad
                // 单例实例存在但不跨场景持久化
                // 使用 base.Instance 静态属性检测重复实例
                var existingInstance = FindObjectOfType<GameManager>();
                if (existingInstance != null && existingInstance != this)
                {
                    Destroy(gameObject);
                    return;
                }
                // 不调用 base.Awake()，避免 DontDestroyOnLoad
            }
            else
            {
                base.Awake();
            }

            InitializeGame();
        }

        public LevelData CurrentLevelData => _currentLevelData;
        public LevelData[] Levels => _levels;

        private void Start()
        {
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "GameScene" || sceneName == "TDGameScene")
            {
                LoadLevel(0);
            }
        }

        public void LoadLevel(int levelIndex)
        {
            if (_levels == null || levelIndex < 0 || levelIndex >= _levels.Length)
            {
                Debug.LogError($"Invalid level index: {levelIndex}");
                return;
            }

            _currentLevelData = _levels[levelIndex];
            _initialGold = _currentLevelData.initialGold;
            _initialLife = _currentLevelData.initialLife;
            InitializeGame();

            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = 0 });
            OnLifeChanged?.Invoke(_currentLife);

            if (_levelBuilder != null)
            {
                _levelBuilder.BuildLevel(_currentLevelData);
            }

            StartGame(_currentLevelData.waves.Count > 0 ? _currentLevelData.waves.Count : _currentLevelData.waveCount);
        }

        private void InitializeGame()
        {
            _currentGold = _initialGold;
            _currentLife = _initialLife;
            _currentState = GameState.Menu;
            _currentWave = 0;
            _enemiesKilled = 0;
            _gameTime = 0f;
        }

        private void Update()
        {
            if (_currentState == GameState.Playing)
            {
                _gameTime += Time.deltaTime * _gameSpeed;
            }

            if (_debugMode)
            {
                HandleDebugInput();
            }
        }

        public void StartGame(int totalWaves)
        {
            _totalWaves = totalWaves;
            _currentState = GameState.Playing;
            _gameTime = 0f;
            Time.timeScale = _gameSpeed;
            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameStartEvent());
        }

        public void PauseGame()
        {
            if (_currentState == GameState.Playing)
            {
                _currentState = GameState.Paused;
                Time.timeScale = 0f;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = true });
            }
        }

        public void ResumeGame()
        {
            if (_currentState == GameState.Paused)
            {
                _currentState = GameState.Playing;
                Time.timeScale = _gameSpeed;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = false });
            }
        }

        public void TogglePause()
        {
            if (_currentState == GameState.Playing)
            {
                PauseGame();
            }
            else if (_currentState == GameState.Paused)
            {
                ResumeGame();
            }
        }

        public void GameOver(bool isVictory)
        {
            _currentState = isVictory ? GameState.Victory : GameState.GameOver;
            Time.timeScale = 0f;

            // 持久化玩家等级数据
            Data.PlayerLevelSystem.Instance?.PersistToSave();

            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameOverEvent { IsVictory = isVictory });

            if (isVictory)
            {
                Data.PlayerLevelSystem.Instance?.AddExp(50 + _currentWave * 10);
            }
            Data.PlayerLevelSystem.Instance?.PersistToSave();

            // 模块模式下发布 MiniGameCompletedEvent
            if (_isModuleMode)
            {
                Sttop5.Shared.Core.GlobalEventBus.Publish(new Sttop5.Shared.Core.MiniGameCompletedEvent
                {
                    ModuleId = "towerdefense",
                    IsVictory = isVictory,
                    StarsEarned = isVictory ? CalculateStars() : 0,
                    GoldReward = isVictory ? _currentWave * 20 : 0,
                    ExpReward = isVictory ? 50 + _currentWave * 10 : 0
                });
            }
        }

        private int CalculateStars()
        {
            float lifeRatio = (float)_currentLife / _initialLife;
            if (lifeRatio >= 0.7f) return 3;
            if (lifeRatio >= 0.4f) return 2;
            return 1;
        }

        public void OnVictory()
        {
            GameOver(true);
        }

        public void RestartGame()
        {
            InitializeGame();
            Time.timeScale = 1f;

            if (_isModuleMode)
            {
                // 模块模式下重载 TDGameScene
                var sceneLoader = Sttop5.Shared.Core.SceneLoader.Instance;
                if (sceneLoader != null)
                {
                    sceneLoader.UnloadScene("TDGameScene", () =>
                    {
                        sceneLoader.LoadSceneAdditive("TDGameScene");
                    });
                }
                else
                {
                    UnityEngine.SceneManagement.SceneManager.LoadScene(
                        UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
                    );
                }
            }
            else
            {
                UnityEngine.SceneManagement.SceneManager.LoadScene(
                    UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
                );
            }
        }

        /// <summary>
        /// 返回家园（模块模式下使用）。
        /// </summary>
        public void ReturnToHome()
        {
            if (_isModuleMode)
            {
                Time.timeScale = 1f;
                Sttop5.Shared.Core.ModuleManager.Instance.DeactivateCurrentModule();
            }
            else
            {
                UnityEngine.SceneManagement.SceneManager.LoadScene("MainMenu");
            }
        }

        #region Gold Management

        public bool HasEnoughGold(int amount)
        {
            return _currentGold >= amount;
        }

        public void AddGold(int amount)
        {
            if (amount <= 0) return;
            _currentGold += amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;
            _currentGold -= amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = -amount });
            return true;
        }

        #endregion

        #region Life Management

        public void TakeDamage(int damage)
        {
            _currentLife -= damage;
            if (_currentLife < 0) _currentLife = 0;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = -damage });

            if (_currentLife <= 0)
            {
                GameOver(false);
            }
        }

        public void Heal(int amount)
        {
            _currentLife += amount;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = amount });
        }

        #endregion

        #region Wave Management

        public void SetCurrentWave(int wave)
        {
            _currentWave = wave;
            OnWaveChanged?.Invoke(_currentWave);
        }

        public void IncrementWave()
        {
            _currentWave++;
            OnWaveChanged?.Invoke(_currentWave);
        }

        #endregion

        #region Statistics

        public void AddKill()
        {
            _enemiesKilled++;
            Data.PlayerLevelSystem.Instance?.AddExp(5);
        }

        #endregion

        #region Debug

        private void HandleDebugInput()
        {
            if (Input.GetKeyDown(KeyCode.F1))
            {
                AddGold(100);
                Debug.Log($"[Debug] Added 100 gold. Current: {_currentGold}");
            }
            if (Input.GetKeyDown(KeyCode.F2))
            {
                _currentLife = _initialLife;
                OnLifeChanged?.Invoke(_currentLife);
                Debug.Log($"[Debug] Life restored to {_currentLife}");
            }
            if (Input.GetKeyDown(KeyCode.F3))
            {
                _gameSpeed = _gameSpeed >= 3f ? 1f : _gameSpeed + 0.5f;
                if (_currentState == GameState.Playing)
                {
                    Time.timeScale = _gameSpeed;
                }
                Debug.Log($"[Debug] Game speed: {_gameSpeed}x");
            }
        }

        #endregion
    }
}

